+	while ((ch = getopt(argc, argv, "B:b:d:f:F:M:m:N:o:ps:S:t:x")) != -1) {
 		switch (ch) {

 		case 'B':
@@ -199,6 +199,9 @@ main(int argc, char *argv[])
 			}
